# Icon Helper - Heroicons (https://heroicons.com)
# Renderiza ícones SVG inline com Tailwind CSS
module IconHelper
  # Renderiza um ícone Heroicon
  # @param name [Symbol] Nome do ícone
  # @param variant [Symbol] :outline ou :solid (padrão: :outline)
  # @param css_class [String] Classes CSS customizadas
  def heroicon(name, variant: :outline, css_class: "w-6 h-6")
    content_tag(:svg,
      heroicon_path(name, variant).html_safe,
      class: css_class,
      fill: variant == :solid ? "currentColor" : "none",
      stroke: variant == :outline ? "currentColor" : "none",
      viewBox: "0 0 24 24",
      "stroke-width": variant == :outline ? "1.5" : "0",
      "aria-hidden": "true"
    )
  end

